  function readLocal(key, fallback){ try { const value = localStorage.getItem(`lumera_${key}`); return value ? JSON.parse(value) : structuredClone(fallback); } catch { return structuredClone(fallback); } }
  function writeLocal(key, value){ localStorage.setItem(`lumera_${key}`, JSON.stringify(value)); }
  async function api(path, options={}){
    if(!CONFIG.apiBase) throw new Error("API_NOT_CONFIGURED");
    const headers={"Content-Type":"application/json",...(options.headers||{})};
    if(state.token) headers.Authorization=`Bearer ${state.token}`;
    const response=await fetch(`${CONFIG.apiBase.replace(/\/$/,"")}${path}`,{...options,headers});
    const data=await response.json().catch(()=>({}));
    if(!response.ok) throw new Error(data.error||"İşlem tamamlanamadı");
    return data;
  }
  async function bootstrap(){
    if(!CONFIG.apiBase){ setStorage(false); return; }
    try{ const data=await api("/api/bootstrap"); if(data.products?.length) state.products=data.products; if(data.settings&&Object.keys(data.settings).length) state.settings={...defaultSettings,...data.settings}; state.reviewStats=data.reviewStats||{}; state.apiOnline=true; setStorage(true); renderAll(); }
    catch{ state.apiOnline=false; setStorage(false); }
  }
  function setStorage(online){ const dot=$("#storageDot"),label=$("#storageLabel"),detail=$("#storageDetail"); if(!dot)return; dot.classList.toggle("online",online); label.textContent=online?"Cloudflare D1 bağlı":"Yerel devamlılık"; detail.textContent=online?"Merkezi veriler eşitleniyor":"API bağlantısı bekleniyor"; }
  function toast(text,ok=true){ const el=$("#toast"); el.textContent=`${ok?"✓":"!"} ${text}`; el.classList.add("show"); clearTimeout(toastTimer); toastTimer=setTimeout(()=>el.classList.remove("show"),2600); }
  function persist(){ writeLocal("products",state.products);writeLocal("cart",state.cart);writeLocal("favorites",state.favorites);writeLocal("settings",state.settings);writeLocal("orders",state.orders);writeLocal("customers",state.customers);writeLocal("coupon",state.coupon); }
